   256→// --- HELPER FUNCTIONS ---
   257→export function extractRecordId(url: string | null | undefined): string | null {
   258→  if (!url) return null;
   259→  // Extrahiere die letzten 24 Hex-Zeichen mit Regex
   260→  const match = url.match(/([a-f0-9]{24})$/i);
   261→  return match ? match[1] : null;
   262→}
   263→
   264→export function createRecordUrl(appId: string, recordId: string): string {
   265→  return `https://my.living-apps.de/rest/apps/${appId}/records/${recordId}`;
   266→}
   267→
   268→async function callApi(method: string, endpoint: string, data?: any) {
   269→  const response = await fetch(`${API_BASE_URL}${endpoint}`, {
   270→    method,
   271→    headers: { 'Content-Type': 'application/json' },
   272→    credentials: 'include',  // Nutze Session Cookies für Auth
   273→    body: data ? JSON.stringify(data) : undefined
   274→  });
   275→  if (!response.ok) throw new Error(await response.text());
   276→  // DELETE returns often empty body or simple status
   277→  if (method === 'DELETE') return true;
   278→  return response.json();
   279→}
   280→
   281→/** Upload a file to LivingApps. Returns the file URL for use in record fields. */
   282→export async function uploadFile(file: File | Blob, filename?: string): Promise<string> {
   283→  const formData = new FormData();
   284→  formData.append('file', file, filename ?? (file instanceof File ? file.name : 'upload'));
   285→  const res = await fetch(`${API_BASE_URL}/files`, {
   286→    method: 'POST',
   287→    credentials: 'include',
   288→    body: formData,
   289→  });
   290→  if (!res.ok) throw new Error(`File upload failed: ${res.status}`);
   291→  const data = await res.json();
   292→  return data.url;
   293→}
