   631→import { useState, useEffect, useMemo, useCallback } from 'react';
   632→import type { Klientenstammdaten, Pflegefachkraefte, Medikamentenplan, Pflegeplanung, Tourenplanung, VitalwerteErfassung, Wunddokumentation, Pflegedurchfuehrung, Leistungsnachweis } from '@/types/app';
   633→import { LivingAppsService } from '@/services/livingAppsService';
   634→
   635→export function useDashboardData() {
   636→  const [klientenstammdaten, setKlientenstammdaten] = useState<Klientenstammdaten[]>([]);
   637→  const [pflegefachkraefte, setPflegefachkraefte] = useState<Pflegefachkraefte[]>([]);
   638→  const [medikamentenplan, setMedikamentenplan] = useState<Medikamentenplan[]>([]);
   639→  const [pflegeplanung, setPflegeplanung] = useState<Pflegeplanung[]>([]);
   640→  const [tourenplanung, setTourenplanung] = useState<Tourenplanung[]>([]);
   641→  const [vitalwerteErfassung, setVitalwerteErfassung] = useState<VitalwerteErfassung[]>([]);
   642→  const [wunddokumentation, setWunddokumentation] = useState<Wunddokumentation[]>([]);
   643→  const [pflegedurchfuehrung, setPflegedurchfuehrung] = useState<Pflegedurchfuehrung[]>([]);
   644→  const [leistungsnachweis, setLeistungsnachweis] = useState<Leistungsnachweis[]>([]);
   645→  const [loading, setLoading] = useState(true);
   646→  const [error, setError] = useState<Error | null>(null);
   647→
   648→  const fetchAll = useCallback(async () => {
   649→    setError(null);
   650→    try {
   651→      const [klientenstammdatenData, pflegefachkraefteData, medikamentenplanData, pflegeplanungData, tourenplanungData, vitalwerteErfassungData, wunddokumentationData, pflegedurchfuehrungData, leistungsnachweisData] = await Promise.all([
   652→        LivingAppsService.getKlientenstammdaten(),
   653→        LivingAppsService.getPflegefachkraefte(),
   654→        LivingAppsService.getMedikamentenplan(),
   655→        LivingAppsService.getPflegeplanung(),
   656→        LivingAppsService.getTourenplanung(),
   657→        LivingAppsService.getVitalwerteErfassung(),
   658→        LivingAppsService.getWunddokumentation(),
   659→        LivingAppsService.getPflegedurchfuehrung(),
   660→        LivingAppsService.getLeistungsnachweis(),
   661→      ]);
   662→      setKlientenstammdaten(klientenstammdatenData);
   663→      setPflegefachkraefte(pflegefachkraefteData);
   664→      setMedikamentenplan(medikamentenplanData);
   665→      setPflegeplanung(pflegeplanungData);
   666→      setTourenplanung(tourenplanungData);
   667→      setVitalwerteErfassung(vitalwerteErfassungData);
   668→      setWunddokumentation(wunddokumentationData);
   669→      setPflegedurchfuehrung(pflegedurchfuehrungData);
   670→      setLeistungsnachweis(leistungsnachweisData);
   671→    } catch (err) {
   672→      setError(err instanceof Error ? err : new Error('Fehler beim Laden der Daten'));
   673→    } finally {
   674→      setLoading(false);
   675→    }
   676→  }, []);
   677→
   678→  useEffect(() => { fetchAll(); }, [fetchAll]);
   679→
   680→  const klientenstammdatenMap = useMemo(() => {
   681→    const m = new Map<string, Klientenstammdaten>();
   682→    klientenstammdaten.forEach(r => m.set(r.record_id, r));
   683→    return m;
   684→  }, [klientenstammdaten]);
   685→
   686→  const pflegefachkraefteMap = useMemo(() => {
   687→    const m = new Map<string, Pflegefachkraefte>();
   688→    pflegefachkraefte.forEach(r => m.set(r.record_id, r));
   689→    return m;
   690→  }, [pflegefachkraefte]);
   691→
   692→  const tourenplanungMap = useMemo(() => {
   693→    const m = new Map<string, Tourenplanung>();
   694→    tourenplanung.forEach(r => m.set(r.record_id, r));
   695→    return m;
   696→  }, [tourenplanung]);
   697→
   698→  return { klientenstammdaten, setKlientenstammdaten, pflegefachkraefte, setPflegefachkraefte, medikamentenplan, setMedikamentenplan, pflegeplanung, setPflegeplanung, tourenplanung, setTourenplanung, vitalwerteErfassung, setVitalwerteErfassung, wunddokumentation, setWunddokumentation, pflegedurchfuehrung, setPflegedurchfuehrung, leistungsnachweis, setLeistungsnachweis, loading, error, fetchAll, klientenstammdatenMap, pflegefachkraefteMap, tourenplanungMap };
   699→}
