   740→## src/lib/enrich.ts
   741→```
   742→import type { EnrichedLeistungsnachweis, EnrichedMedikamentenplan, EnrichedPflegedurchfuehrung, EnrichedPflegeplanung, EnrichedTourenplanung, EnrichedVitalwerteErfassung, EnrichedWunddokumentation } from '@/types/enriched';
   743→import type { Klientenstammdaten, Leistungsnachweis, Medikamentenplan, Pflegedurchfuehrung, Pflegefachkraefte, Pflegeplanung, Tourenplanung, VitalwerteErfassung, Wunddokumentation } from '@/types/app';
   744→import { extractRecordId } from '@/services/livingAppsService';
   745→
   746→// eslint-disable-next-line @typescript-eslint/no-explicit-any
   747→function resolveDisplay(url: string | undefined, map: Map<string, any>, ...fields: string[]): string {
   748→  if (!url) return '';
   749→  const id = extractRecordId(url);
   750→  if (!id) return '';
   751→  const r = map.get(id);
   752→  if (!r) return '';
   753→  return fields.map(f => String(r.fields[f] ?? '')).join(' ').trim();
   754→}
   755→
   756→interface MedikamentenplanMaps {
   757→  klientenstammdatenMap: Map<string, Klientenstammdaten>;
   758→}
   759→
   760→export function enrichMedikamentenplan(
   761→  medikamentenplan: Medikamentenplan[],
   762→  maps: MedikamentenplanMaps
   763→): EnrichedMedikamentenplan[] {
   764→  return medikamentenplan.map(r => ({
   765→    ...r,
   766→    klientName: resolveDisplay(r.fields.klient, maps.klientenstammdatenMap, 'vorname', 'nachname'),
   767→  }));
   768→}
   769→
   770→interface PflegeplanungMaps {
   771→  klientenstammdatenMap: Map<string, Klientenstammdaten>;
   772→  pflegefachkraefteMap: Map<string, Pflegefachkraefte>;
   773→}
   774→
   775→export function enrichPflegeplanung(
   776→  pflegeplanung: Pflegeplanung[],
   777→  maps: PflegeplanungMaps
   778→): EnrichedPflegeplanung[] {
   779→  return pflegeplanung.map(r => ({
   780→    ...r,
   781→    klientName: resolveDisplay(r.fields.klient, maps.klientenstammdatenMap, 'vorname', 'nachname'),
   782→    erstellende_pflegekraftName: resolveDisplay(r.fields.erstellende_pflegekraft, maps.pflegefachkraefteMap, 'vorname', 'nachname'),
   783→  }));
   784→}
   785→
   786→interface TourenplanungMaps {
   787→  pflegefachkraefteMap: Map<string, Pflegefachkraefte>;
   788→  klientenstammdatenMap: Map<string, Klientenstammdaten>;
   789→}
   790→
   791→export function enrichTourenplanung(
   792→  tourenplanung: Tourenplanung[],
   793→  maps: TourenplanungMaps
   794→): EnrichedTourenplanung[] {
   795→  return tourenplanung.map(r => ({
   796→    ...r,
   797→    zugeordnete_pflegekraefteName: resolveDisplay(r.fields.zugeordnete_pflegekraefte, maps.pflegefachkraefteMap, 'vorname', 'nachname'),
   798→    klientenName: resolveDisplay(r.fields.klienten, maps.klientenstammdatenMap, 'vorname', 'nachname'),
   799→  }));
   800→}
   801→
   802→interface VitalwerteErfassungMaps {
   803→  klientenstammdatenMap: Map<string, Klientenstammdaten>;
   804→}
   805→
   806→export function enrichVitalwerteErfassung(
   807→  vitalwerteErfassung: VitalwerteErfassung[],
