   910→const AI_ENDPOINT = "https://my.living-apps.de/litellm/v1/chat/completions";
   911→const AI_MODEL = "default";
   912→
   913→export type ChatMessage = {
   914→  role: "system" | "user" | "assistant";
   915→  content: string | Array<{ type: string; [key: string]: unknown }>;
   916→};
   917→
   918→type CompletionOptions = {
   919→  temperature?: number;
   920→  max_tokens?: number;
   921→  top_p?: number;
   922→  stop?: string[];
   923→  response_format?: { type: string };
   924→};
   925→
   926→export async function chatCompletion(
   927→  messages: ChatMessage[],
   928→  options: CompletionOptions = {}
   929→): Promise<string> {
   930→  const res = await fetch(AI_ENDPOINT, {
   931→    method: "POST",
   932→    headers: { "Content-Type": "application/json", Accept: "application/json" },
   933→    body: JSON.stringify({ model: AI_MODEL, messages, ...options }),
   934→  });
   935→  if (!res.ok) {
   936→    const body = await res.text();
   937→    throw new Error(`AI API ${res.status}: ${body}`);
   938→  }
   939→  const data = await res.json();
   940→  return data.choices[0].message.content;
   941→}
   942→
   943→export async function safeJsonCompletion<T = unknown>(
   944→  messages: ChatMessage[],
   945→  options: CompletionOptions = {}
   946→): Promise<T> {
   947→  const raw = await chatCompletion(messages, options);
   948→  const match = raw.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
   949→  if (!match) throw new Error(`Expected JSON but got: ${raw.slice(0, 200)}`);
   950→  return JSON.parse(match[0]);
   951→}
   952→
   953→export async function withRetry<T>(fn: () => Promise<T>, maxAttempts = 3): Promise<T> {
   954→  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
   955→    try {
   956→      return await fn();
   957→    } catch (err) {
   958→      if (attempt === maxAttempts) throw err;
   959→      await new Promise((r) => setTimeout(r, 1000 * attempt));
   960→    }
   961→  }
   962→  throw new Error("unreachable");
   963→}
   964→
   965→// --- File encoding helpers ---
   966→
   967→export function fileToDataUri(file: File): Promise<string> {
   968→  return new Promise((resolve, reject) => {
   969→    const reader = new FileReader();
   970→    reader.onload = () => resolve(reader.result as string);
   971→    reader.onerror = () => reject(new Error("Failed to read file"));
   972→    reader.readAsDataURL(file);
   973→  });
   974→}
   975→
   976→export async function urlToDataUri(url: string): Promise<string> {
   977→  const res = await fetch(url);
   978→  const blob = await res.blob();
   979→  return new Promise((resolve, reject) => {
   980→    const reader = new FileReader();
   981→    reader.onload = () => resolve(reader.result as string);
   982→    reader.onerror = () => reject(new Error("Failed to encode file"));
   983→    reader.readAsDataURL(blob);
   984→  });
   985→}
   986→
   987→/** Convert a data URI back to a Blob (for file uploads) */
   988→export function dataUriToBlob(dataUri: string): Blob {
   989→  const [header, base64] = dataUri.split(',');
   990→  const mime = header.match(/:(.*?);/)?.[1] ?? 'application/octet-stream';
   991→  const bytes = atob(base64);
   992→  const arr = new Uint8Array(bytes.length);
   993→  for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
   994→  return new Blob([arr], { type: mime });
   995→}
