  1035→  options: { maxSentences?: number; language?: string } = {}
  1036→): Promise<string> {
  1037→  const { maxSentences = 3, language } = options;
  1038→  const instructions = [
  1039→    `Summarize the following text in at most ${maxSentences} sentences.`,
  1040→    "Be concise and preserve key facts.",
  1041→  ];
  1042→  if (language) instructions.push(`Write the summary in ${language}.`);
  1043→  return chatCompletion([
