  1092→  const isImage = dataUri.startsWith("data:image/");
  1093→  const fileContent = isImage
  1094→    ? { type: "image_url" as const, image_url: { url: dataUri } }
  1095→    : { type: "file" as const, file: { file_data: dataUri } };
  1096→  return safeJsonCompletion([
  1097→    {
  1098→      role: "system",
  1099→      content: [
  1100→        "Extract structured data from the provided " + (isImage ? "image" : "document") + ".",
  1101→        "Respond ONLY with valid JSON matching the schema.",
  1102→        "Use null for any field that cannot be determined.",
  1103→        `Schema:\n${schemaDescription}`,
