  1105→    },
  1106→    {
  1107→      role: "user",
  1108→      content: [
  1109→        { type: "text", text: "Extract the data from this " + (isImage ? "image" : "document") + "." },
  1110→        fileContent,
  1111→      ],
  1112→    },
