        klientenstammdatenList={klientenstammdaten}
        enablePhotoScan={AI_PHOTO_SCAN['Tourenplanung']}
      />

      <ConfirmDialog
        open={!!deleteTourTarget}
        title="Tour löschen"
        description={`Tour "${deleteTourTarget?.fields.tourbezeichnung ?? ''}" wirklich löschen?`}
